window.__BRAND_KIT_FILES = {
  "Containers.jsx": "// ═══════════════════════════════════════════════════════════════════\n//  PADELMATCH BRAND KIT — CONTAINER COMPONENTS\n//\n//  Six types (A-F) + NetDivider. Each maps to a semantic context.\n//  See README.md / Brand Kit HTML reference for decision rules.\n// ═══════════════════════════════════════════════════════════════════\n\nimport React from 'react';\nimport { T } from './tokens';\n\n// ── TYPE A — Closed Primary ───────────────────────────────────────\n//  Use for: Game Card, Player Card, Shot Card, Venue Card\nexport function ContainerA({ children, accentColor, style = {}, ...rest }) {\n  return (\n    <div style={{\n      border: `${T.s3} solid ${T.ink}`,\n      background: T.white,\n      overflow: 'hidden',\n      ...style,\n    }} {...rest}>\n      {accentColor && <div style={{ height: T.accentTop, background: accentColor }} />}\n      {children}\n    </div>\n  );\n}\n\n// ── TYPE B — Corner Mark ──────────────────────────────────────────\n//  Use for: Stat Block, Rating Display, Radar Chart, Sparkline\nexport function ContainerB({ children, color = T.ink, size = 16, weight = 2, style = {}, ...rest }) {\n  const corners = [['top','left'],['top','right'],['bottom','left'],['bottom','right']];\n  return (\n    <div style={{ position: 'relative', ...style }} {...rest}>\n      {corners.map(([v, h]) => (\n        <div key={`${v}${h}`} style={{\n          position: 'absolute',\n          [v]: 0, [h]: 0,\n          width: size, height: size,\n          [`border${v[0].toUpperCase()}${v.slice(1)}`]: `${weight}px solid ${color}`,\n          [`border${h[0].toUpperCase()}${h.slice(1)}`]: `${weight}px solid ${color}`,\n          pointerEvents: 'none',\n        }} />\n      ))}\n      {children}\n    </div>\n  );\n}\n\n// ── TYPE C — Left Accent ──────────────────────────────────────────\n//  Use for: Notification, Match Banner, Connection State\n//  accentColor = semantic state: lime/blue/purple/error\nexport function ContainerC({ children, accentColor = T.blue, style = {}, ...rest }) {\n  return (\n    <div style={{\n      display: 'flex',\n      border: `${T.s2} solid ${T.ink}`,\n      background: T.white,\n      overflow: 'hidden',\n      ...style,\n    }} {...rest}>\n      <div style={{ width: T.accentLeft, background: accentColor, flexShrink: 0 }} />\n      <div style={{ flex: 1 }}>{children}</div>\n    </div>\n  );\n}\n\n// ── TYPE D — Top Accent / Header Band ────────────────────────────\n//  Use for: Section Header, Profile Header, Modal Header\nexport function ContainerD({\n  children, accentColor = T.blue, label, labelColor = T.white,\n  style = {}, ...rest\n}) {\n  return (\n    <div style={{\n      border: `${T.s2} solid ${T.ink}`,\n      background: T.white,\n      overflow: 'hidden',\n      ...style,\n    }} {...rest}>\n      {label && (\n        <div style={{\n          background: accentColor,\n          padding: `${T.sp2} ${T.sp4}`,\n          borderBottom: `${T.s2} solid ${T.ink}`,\n          fontFamily: \"'Unbounded', sans-serif\",\n          fontSize: 8, fontWeight: 700, letterSpacing: '0.12em',\n          textTransform: 'uppercase', color: labelColor,\n        }}>{label}</div>\n      )}\n      {children}\n    </div>\n  );\n}\n\n// ── TYPE E — Open-Sided ──────────────────────────────────────────\n//  Use for: Pending Match, Score Pending, Awaiting Confirmation\nexport function ContainerE({ children, openSide = 'bottom', style = {}, ...rest }) {\n  const borders = {\n    borderTop:    openSide !== 'top'    ? `${T.s2} solid ${T.ink}` : 'none',\n    borderRight:  openSide !== 'right'  ? `${T.s2} solid ${T.ink}` : 'none',\n    borderBottom: openSide !== 'bottom' ? `${T.s2} solid ${T.ink}` : 'none',\n    borderLeft:   openSide !== 'left'   ? `${T.s2} solid ${T.ink}` : 'none',\n  };\n  return <div style={{ background: T.white, ...borders, ...style }} {...rest}>{children}</div>;\n}\n\n// ── TYPE F — Dashed Input ─────────────────────────────────────────\n//  Use for: Empty Player Slot, Add Connection, File Upload Zone\nexport function ContainerF({ children, style = {}, ...rest }) {\n  return (\n    <div style={{\n      border: `${T.s2} dashed ${T.border}`,\n      background: T.white,\n      transition: 'border-color 150ms ease',\n      ...style,\n    }} {...rest}>{children}</div>\n  );\n}\n\n// ── NetDivider — the padel net as horizontal divider ─────────────\n//  Use for: section dividers, replaces <hr>\nexport function NetDivider({ color = T.ink, opacity = 0.15, style = {} }) {\n  return (\n    <svg width=\"100%\" height=\"8\" preserveAspectRatio=\"none\" viewBox=\"0 0 400 8\" style={{ display: 'block', ...style }}>\n      <line x1=\"0\" y1=\"1\" x2=\"400\" y2=\"1\" stroke={color} strokeWidth=\"1.5\" strokeOpacity={opacity * 1.6} />\n      <line x1=\"0\" y1=\"7\" x2=\"400\" y2=\"7\" stroke={color} strokeWidth=\"1\"   strokeOpacity={opacity} />\n      {Array.from({ length: 67 }, (_, i) => (\n        <line key={i} x1={i * 6} y1=\"1\" x2={i * 6} y2=\"7\"\n              stroke={color} strokeWidth=\"0.5\" strokeOpacity={opacity * 0.55} />\n      ))}\n    </svg>\n  );\n}\n",
  "Logo.jsx": "// ═══════════════════════════════════════════════════════════════════\n//  PADELMATCH BRAND KIT — LOGO COMPONENTS\n//\n//  <Logo size={48} cellFills={{ TL: '#1A56FF', BR: '#C9E52F' }} />\n//  <Lockup size={200} showTagline />\n//  <Lockup size={200} onInk />\n//\n//  For pixel-perfect mark/wordmark alignment with calibrated font\n//  metrics, see /lib/renderLockup.js — this file is the simple, fast,\n//  declarative version that covers 95% of use cases.\n// ═══════════════════════════════════════════════════════════════════\n\nimport React from 'react';\nimport { LOGO_GEOMETRY as G } from './logo-geometry';\nimport { T, F } from './tokens';\n\nconst DEFAULT_FILLS = { TL: T.blue, BR: T.lime };\n\nexport function Logo({\n  size = 64,                     // height in px (mark is 2.5:1 so width = size * 2.5)\n  cellFills = DEFAULT_FILLS,\n  onInk = false,\n  letter = null,                 // 'P' or 'M' for monogram overlay\n  className,\n  style = {},\n}) {\n  const stroke = onInk ? T.white : T.ink;\n  const letterRects = letter ? G.letterRects[letter] : null;\n  const letterColor = letter === 'P' ? T.lime : T.blue;\n\n  return (\n    <svg\n      width={size * G.aspectRatio}\n      height={size}\n      viewBox={G.viewBox}\n      className={className}\n      style={{ display: 'inline-block', ...style }}\n    >\n      {/* Cell fills */}\n      {!letter && Object.entries(cellFills).map(([cell, color]) => {\n        const c = G.cells[cell];\n        if (!c || !color) return null;\n        return <rect key={cell} x={c.x} y={c.y} width={c.w} height={c.h} fill={color} />;\n      })}\n\n      {/* Court frame (cages + outer walls) */}\n      <path d={G.courtPath} fill={stroke} fillRule=\"evenodd\" />\n\n      {/* Net — always solid stroke colour */}\n      <rect x={G.net.x} y={G.net.y} width={G.net.w} height={G.net.h} fill={stroke} />\n\n      {/* Optional letter monogram overlay */}\n      {letterRects && letterRects.map((r, i) => (\n        <rect key={i} x={r.x} y={r.y} width={r.w} height={r.h} fill={letterColor} />\n      ))}\n    </svg>\n  );\n}\n\n// ═══════════════════════════════════════════════════════════════════\n//  Lockup — mark + wordmark (+ optional tagline) horizontally\n//\n//  Mark height : wordmark cap-height : tagline cap-height alignment is\n//  calibrated by font metrics. For Unbounded 900 + DM Mono these\n//  approximations give visually-flush horizontal lockups. For exact\n//  metric calibration, see /lib/lockup-metrics.js\n// ═══════════════════════════════════════════════════════════════════\n\nconst CAP_RATIO_WM  = 0.73;  // Unbounded 900 cap-height / em\nconst CAP_RATIO_TAG = 0.70;  // DM Mono cap-height / em\nconst TAG_FONT_RATIO = 0.30; // tagline size / wordmark size\nconst TAG_GAP_RATIO  = 0.18; // gap between wm baseline and tag cap-top, fraction of wm size\nconst VIS_COURT_RATIO = 32 / 36; // visible court height / svg box height\n\nexport function Lockup({\n  size = 200,                   // mark width in px\n  showTagline = false,\n  tagline = 'Find the perfect match.',\n  onInk = false,\n  cellFills = DEFAULT_FILLS,\n  className,\n  style = {},\n}) {\n  const markBoxH = size / G.aspectRatio;\n  const visMarkH = markBoxH * VIS_COURT_RATIO;\n  const visMarkTopOffset = markBoxH * (2 / 36);\n\n  let wmSize;\n  if (showTagline) {\n    wmSize = visMarkH / (CAP_RATIO_WM + TAG_GAP_RATIO + TAG_FONT_RATIO * CAP_RATIO_TAG);\n  } else {\n    wmSize = visMarkH / CAP_RATIO_WM;\n  }\n  const tagSize = wmSize * TAG_FONT_RATIO;\n  const tagGap  = wmSize * TAG_GAP_RATIO;\n  const gap     = markBoxH * 0.20;\n\n  const inkBase = onInk ? T.white : T.ink;\n  const tagColor = onInk ? 'rgba(255,255,255,0.55)' : 'rgba(17,17,24,0.55)';\n\n  return (\n    <div className={className} style={{ display: 'inline-flex', alignItems: 'flex-start', gap, ...style }}>\n      <div style={{ marginTop: -visMarkTopOffset }}>\n        <Logo size={markBoxH} cellFills={cellFills} onInk={onInk} />\n      </div>\n      <div style={{ display: 'flex', flexDirection: 'column', gap: tagGap }}>\n        <span style={{\n          fontFamily: F.display,\n          fontWeight: 900,\n          fontSize: wmSize,\n          letterSpacing: '-0.04em',\n          lineHeight: 1,\n          color: inkBase,\n        }}>\n          PADEL <span style={{ color: T.lime }}>MATCH</span>\n        </span>\n        {showTagline && (\n          <span style={{\n            fontFamily: F.mono,\n            fontWeight: 400,\n            fontSize: tagSize,\n            letterSpacing: '0.12em',\n            textTransform: 'uppercase',\n            lineHeight: 1,\n            color: tagColor,\n          }}>{tagline.toUpperCase()}</span>\n        )}\n      </div>\n    </div>\n  );\n}\n\n// Mark-only convenience export\nexport function Mark(props) {\n  return <Logo {...props} />;\n}\n",
  "README.md": "# PadelMatch Brand Kit · v1.0\n\nDrop-in design system for PadelMatch. Built for **Claude Code** and **emergent.sh** — every file is self-contained and zero-dep (except React peer for `.jsx`).\n\n## Quick start\n\n```bash\n# 1. Copy these files into your project (suggested layout):\nsrc/styles/tokens.css          # ← CSS custom properties\nsrc/styles/containers.css      # ← .pm-card-* classes\nsrc/styles/textures.css        # ← .pm-texture-* classes\nsrc/lib/tokens.js              # ← T and F token objects\nsrc/lib/logo-geometry.js       # ← source-of-truth mark geometry\nsrc/components/Logo.jsx        # ← Logo + Lockup components\nsrc/components/Containers.jsx  # ← ContainerA-F + NetDivider\nsrc/components/Textures.jsx    # ← TX background generators\n\n# 2. Import the CSS once at app root:\nimport './styles/tokens.css';\nimport './styles/containers.css';\nimport './styles/textures.css';\n\n# 3. Load fonts (in <head>):\n<link rel=\"preconnect\" href=\"https://fonts.googleapis.com\">\n<link rel=\"preconnect\" href=\"https://fonts.gstatic.com\" crossorigin>\n<link href=\"https://fonts.googleapis.com/css2?family=Unbounded:wght@400;700;900&family=DM+Sans:wght@300;400;500;600&family=DM+Mono:wght@400;500&display=swap\" rel=\"stylesheet\">\n```\n\n## Files\n\n| File | Purpose |\n|---|---|\n| `tokens.css` | All CSS custom properties — colours, strokes, spacing, opacities |\n| `tokens.js` | Same tokens as a JS object (`T`, `F`) for React/JSX use |\n| `containers.css` | Class-based implementations of Type A–F containers |\n| `textures.css` | Five padel-derived background textures (perforations, court lines, glass panels, wire fence) |\n| `logo-geometry.js` | The mark as data — cells, court path, net — so you can render it without an SVG file |\n| `Logo.jsx` | React `<Logo>` + `<Lockup>` components |\n| `Containers.jsx` | React `<ContainerA>` through `<ContainerF>` + `<NetDivider>` |\n| `Textures.jsx` | React `TX` helper that returns inline-style objects |\n\n## Design system summary\n\n**Sport Brutalism.** Bold, unsentimental, typographic. Treats data like a scoreboard.\n\n- **Colours:** Lime #C9E52F (primary), Blue #1A56FF (secondary), Purple #6E28D9 (tertiary), Ink #111118, Cream #F5F2E8, Coral #FF4136 (error only)\n- **Type:** Unbounded (display), DM Sans (body), DM Mono (scores/stats)\n- **Strokes:** 1px internal · 2px default · 3px primary structural\n- **Containers:** Six types (A-F) — each maps to a semantic context\n- **Textures:** All derived from the physical padel court at 4–8% opacity\n\nSee the full Brand Kit HTML reference for usage rules, examples, and quick-reference decision rules.\n\n## Decision rules\n\n| Question | Answer |\n|---|---|\n| Is this interactive? | Type A (3px border) or D (top band). Dashed if awaiting input → F. |\n| Read-only information? | Type B (corner marks). |\n| Status / notification? | Type C — left accent in semantic colour. |\n| In-progress / incomplete? | Type E — open-sided. |\n| Stroke weight? | 1px = internal rows. 2px = default. 3px = primary, one per cluster. |\n| Top accent meaning? | The *category* of card content. |\n| Left accent meaning? | The *status / state* right now. |\n| When do I use coral? | Errors, unavailable, losses. Never decoratively. |\n\n## License\n\nInternal use for PadelMatch. Not for public distribution without permission.\n",
  "Textures.jsx": "// ═══════════════════════════════════════════════════════════════════\n//  PADELMATCH BRAND KIT — TEXTURE HELPERS\n//\n//  Generators that return inline-style objects. Use directly:\n//    <div style={{ ...TX.perforations(), height: 200 }} />\n//    <div style={TX.courtLines(0.05, T.lime)} />\n//\n//  Or use the class-based versions from /styles/textures.css:\n//    <div className=\"pm-texture-perforations\" />\n// ═══════════════════════════════════════════════════════════════════\n\nimport { T } from './tokens';\n\nconst _hex = (opacity) =>\n  Math.round(opacity * 255).toString(16).padStart(2, '0');\n\nexport const TX = {\n  perforations: (opacity = T.txStandard, color = T.ink) => ({\n    backgroundImage: `radial-gradient(circle, ${color}${_hex(opacity)} 1.5px, transparent 1.5px)`,\n    backgroundSize: '14px 14px',\n  }),\n  courtLines: (opacity = T.txStandard, color = T.ink) => ({\n    backgroundImage: [\n      `repeating-linear-gradient(0deg, transparent, transparent 29px, ${color}${_hex(opacity)} 30px)`,\n      `repeating-linear-gradient(90deg, transparent, transparent 59px, ${color}${_hex(opacity)} 60px)`,\n    ].join(', '),\n  }),\n  glassPanels: (opacity = T.txStandard, color = T.ink) => ({\n    backgroundImage: [\n      `repeating-linear-gradient(0deg, transparent, transparent 43px, ${color}${_hex(opacity)} 44px)`,\n      `repeating-linear-gradient(90deg, transparent, transparent 87px, ${color}${_hex(opacity)} 88px)`,\n    ].join(', '),\n  }),\n  wireFence: (opacity = T.txStandard, color = T.ink) => ({\n    backgroundImage: [\n      `repeating-linear-gradient(45deg, ${color}${_hex(opacity)} 0, ${color}${_hex(opacity)} 1px, transparent 0, transparent 50%)`,\n      `repeating-linear-gradient(-45deg, ${color}${_hex(opacity)} 0, ${color}${_hex(opacity)} 1px, transparent 0, transparent 50%)`,\n    ].join(', '),\n    backgroundSize: '10px 10px',\n  }),\n};\n",
  "containers.css": "/* ═══════════════════════════════════════════════════════════════════\n   PADELMATCH BRAND KIT — CONTAINER CLASSES\n   Six container types map to specific semantic contexts.\n   ═══════════════════════════════════════════════════════════════════ */\n\n/* Type A — Closed Primary\n   Use for: Game Card, Player Card, Shot Card, Venue Card */\n.pm-card-a {\n  border: var(--pm-s3) solid var(--pm-ink);\n  background: var(--pm-white);\n  overflow: hidden;\n}\n.pm-card-a > .pm-accent-top {\n  height: var(--pm-accent-top);\n  background: var(--pm-blue);\n}\n.pm-card-a > .pm-accent-top--lime   { background: var(--pm-lime); }\n.pm-card-a > .pm-accent-top--blue   { background: var(--pm-blue); }\n.pm-card-a > .pm-accent-top--purple { background: var(--pm-purple); }\n\n/* Type B — Corner Mark\n   Use for: Stat Block, Rating Display, Radar Chart, Sparkline */\n.pm-card-b {\n  position: relative;\n  padding: var(--pm-sp4);\n}\n.pm-card-b::before,\n.pm-card-b::after,\n.pm-card-b > .pm-corner-bl,\n.pm-card-b > .pm-corner-br {\n  content: '';\n  position: absolute;\n  width: var(--pm-corner-mark);\n  height: var(--pm-corner-mark);\n  border-color: var(--pm-ink);\n  border-style: solid;\n  border-width: 0;\n  pointer-events: none;\n}\n.pm-card-b::before {\n  top: 0; left: 0;\n  border-top-width: var(--pm-s2);\n  border-left-width: var(--pm-s2);\n}\n.pm-card-b::after {\n  top: 0; right: 0;\n  border-top-width: var(--pm-s2);\n  border-right-width: var(--pm-s2);\n}\n.pm-card-b > .pm-corner-bl {\n  bottom: 0; left: 0;\n  border-bottom-width: var(--pm-s2);\n  border-left-width: var(--pm-s2);\n}\n.pm-card-b > .pm-corner-br {\n  bottom: 0; right: 0;\n  border-bottom-width: var(--pm-s2);\n  border-right-width: var(--pm-s2);\n}\n\n/* Type C — Left Accent\n   Use for: Notification Row, Match Banner, Connection State */\n.pm-card-c {\n  display: flex;\n  border: var(--pm-s2) solid var(--pm-ink);\n  background: var(--pm-white);\n  overflow: hidden;\n}\n.pm-card-c > .pm-left-accent {\n  width: var(--pm-accent-left);\n  flex-shrink: 0;\n  background: var(--pm-blue);\n}\n.pm-card-c > .pm-left-accent--lime   { background: var(--pm-lime); }\n.pm-card-c > .pm-left-accent--blue   { background: var(--pm-blue); }\n.pm-card-c > .pm-left-accent--purple { background: var(--pm-purple); }\n.pm-card-c > .pm-left-accent--error  { background: var(--pm-error); }\n.pm-card-c > .pm-card-c__body { flex: 1; padding: var(--pm-sp3) var(--pm-sp4); }\n\n/* Type D — Top Accent / Header Band\n   Use for: Section Header, Profile Header, Modal Header */\n.pm-card-d {\n  border: var(--pm-s2) solid var(--pm-ink);\n  background: var(--pm-white);\n  overflow: hidden;\n}\n.pm-card-d > .pm-header-band {\n  background: var(--pm-blue);\n  padding: var(--pm-sp2) var(--pm-sp4);\n  border-bottom: var(--pm-s2) solid var(--pm-ink);\n  font-family: var(--pm-font-display);\n  font-size: 8px;\n  font-weight: 700;\n  letter-spacing: 0.12em;\n  text-transform: uppercase;\n  color: var(--pm-white);\n}\n.pm-card-d > .pm-header-band--purple { background: var(--pm-purple); }\n.pm-card-d > .pm-header-band--lime   { background: var(--pm-lime); color: var(--pm-ink); }\n.pm-card-d > .pm-header-band--ink    { background: var(--pm-ink); color: var(--pm-lime); }\n\n/* Type E — Open-Sided\n   Use for: Pending Match, Score Pending, Awaiting Confirmation */\n.pm-card-e {\n  background: var(--pm-white);\n  border-top:    var(--pm-s2) solid var(--pm-ink);\n  border-right:  var(--pm-s2) solid var(--pm-ink);\n  border-left:   var(--pm-s2) solid var(--pm-ink);\n}\n.pm-card-e--open-top    { border-top: none;    border-bottom: var(--pm-s2) solid var(--pm-ink); }\n.pm-card-e--open-right  { border-right: none; }\n.pm-card-e--open-left   { border-left: none;  border-right: var(--pm-s2) solid var(--pm-ink); }\n\n/* Type F — Dashed Input\n   Use for: Empty Player Slot, Add Connection, File Upload Zone */\n.pm-card-f {\n  border: var(--pm-s2) dashed var(--pm-border);\n  background: var(--pm-white);\n  transition: border-color 150ms ease;\n}\n.pm-card-f:hover,\n.pm-card-f:focus-within {\n  border-color: var(--pm-ink);\n}\n\n/* Glass inset — optional decorative inner border for Type A primary cards */\n.pm-glass-inset { position: relative; }\n.pm-glass-inset::after {\n  content: '';\n  position: absolute;\n  inset: var(--pm-inner-inset);\n  border: 1px solid var(--pm-ink);\n  opacity: 0.07;\n  pointer-events: none;\n}\n",
  "logo-geometry.js": "// ═══════════════════════════════════════════════════════════════════\n//  PADELMATCH LOGO GEOMETRY — source of truth\n//  Use to render the mark anywhere without an SVG file.\n// ═══════════════════════════════════════════════════════════════════\n\nexport const LOGO_GEOMETRY = {\n  viewBox: \"5 30 90 36\",\n  aspectRatio: 2.5,  // width / height\n\n  // Six interior cells (TL/TR top-left/right, BL/BR bottom-left/right, L/R outer strips)\n  cells: {\n    L:  { x:  7,   y: 32, w:  3,   h: 32 },   // outer-left strip (not normally filled)\n    TL: { x: 23,   y: 35, w: 23,   h: 13 },   // top-left\n    BL: { x: 23,   y: 49, w: 23,   h: 12.5 },// bottom-left\n    TR: { x: 54,   y: 35, w: 23,   h: 13 },   // top-right\n    BR: { x: 54,   y: 49, w: 23,   h: 12.5 },// bottom-right\n    R:  { x: 90,   y: 32, w:  3,   h: 32 },   // outer-right strip\n  },\n\n  // The two cages and net as a single fill-rule=\"evenodd\" path\n  // (this is approximate — for pixel-perfect use, import the SVG directly)\n  courtPath: \"M 11 32 L 45 32 A 2 2 0 0 1 47 34 L 47 62 A 2 2 0 0 1 45 64 L 11 64 A 4 4 0 0 1 7 60 L 7 36 A 4 4 0 0 1 11 32 Z M 10 35 L 10 61 L 20 61 L 20 49.5 L 46 49.5 L 46 46 L 20 46 L 20 35 Z M 55 32 L 89 32 A 4 4 0 0 1 93 36 L 93 60 A 4 4 0 0 1 89 64 L 55 64 A 2 2 0 0 1 53 62 L 53 34 A 2 2 0 0 1 55 32 Z M 90 35 L 80 35 L 80 46 L 54 46 L 54 49.5 L 80 49.5 L 80 61 L 90 61 Z\",\n\n  // Central net (always solid ink/white, never coloured)\n  net: { x: 47.5, y: 35, w: 5, h: 26 },\n\n  // Letter monogram overlays — sit exactly on existing court walls\n  letterRects: {\n    P: [\n      { x: 20, y: 32,   w: 3,  h: 32 },   // spine\n      { x: 20, y: 32,   w: 26, h: 3  },   // top bowl\n      { x: 20, y: 46.5, w: 26, h: 3  },   // bottom of bowl\n      { x: 46, y: 35,   w: 3,  h: 14 },   // right of bowl\n    ],\n    M: [\n      { x: 7,    y: 32, w: 3,  h: 32 },   // left leg\n      { x: 91,   y: 32, w: 3,  h: 32 },   // right leg\n      { x: 7,    y: 32, w: 87, h: 3  },   // top connector\n      { x: 46,   y: 35, w: 9,  h: 13 },   // top of central stem\n    ],\n  },\n};\n",
  "textures.css": "/* ═══════════════════════════════════════════════════════════════════\n   PADELMATCH BRAND KIT — TEXTURE CLASSES\n   Five padel-derived patterns. Apply at 4-8% opacity as backgrounds.\n   ═══════════════════════════════════════════════════════════════════ */\n\n/* PERFORATIONS — racket holes. Default ink on light, lime on ink */\n.pm-texture-perforations {\n  background-image: radial-gradient(\n    circle, rgba(17, 17, 24, 0.06) 1.5px, transparent 1.5px\n  );\n  background-size: 14px 14px;\n}\n.pm-texture-perforations-lime {\n  background-image: radial-gradient(\n    circle, rgba(201, 229, 47, 0.07) 1.5px, transparent 1.5px\n  );\n  background-size: 14px 14px;\n}\n\n/* COURT LINES — top-down service quadrant grid */\n.pm-texture-court-lines {\n  background-image:\n    repeating-linear-gradient(0deg,  transparent, transparent 29px, rgba(17, 17, 24, 0.05) 30px),\n    repeating-linear-gradient(90deg, transparent, transparent 59px, rgba(17, 17, 24, 0.05) 60px);\n}\n.pm-texture-court-lines-lime {\n  background-image:\n    repeating-linear-gradient(0deg,  transparent, transparent 29px, rgba(201, 229, 47, 0.05) 30px),\n    repeating-linear-gradient(90deg, transparent, transparent 59px, rgba(201, 229, 47, 0.05) 60px);\n}\n\n/* GLASS PANELS — 3x2 grid of cage panels */\n.pm-texture-glass-panels {\n  background-image:\n    repeating-linear-gradient(0deg,  transparent, transparent 43px, rgba(17, 17, 24, 0.05) 44px),\n    repeating-linear-gradient(90deg, transparent, transparent 87px, rgba(17, 17, 24, 0.05) 88px);\n}\n\n/* WIRE FENCE — diamond chainlink. Use for empty/off-limits */\n.pm-texture-wire-fence {\n  background-image:\n    repeating-linear-gradient(45deg,  rgba(17, 17, 24, 0.05) 0, rgba(17, 17, 24, 0.05) 1px, transparent 0, transparent 50%),\n    repeating-linear-gradient(-45deg, rgba(17, 17, 24, 0.05) 0, rgba(17, 17, 24, 0.05) 1px, transparent 0, transparent 50%);\n  background-size: 10px 10px;\n}\n",
  "tokens.css": "/* ═══════════════════════════════════════════════════════════════════\n   PADELMATCH BRAND KIT — DESIGN TOKENS (CSS)\n   Drop into any project. Import once at app root.\n   ═══════════════════════════════════════════════════════════════════ */\n\n:root {\n  /* ── COLOURS ───────────────────────────── */\n  --pm-lime:    #C9E52F;   /* Primary — CTAs, active nav, rating, #1 rank */\n  --pm-blue:    #1A56FF;   /* Secondary — rank, section headers, later-slots */\n  --pm-purple:  #6E28D9;   /* Tertiary — profile, info, connections */\n  --pm-ink:     #111118;   /* Anchor — type, borders, nav bg */\n  --pm-cream:   #F5F2E8;   /* Background — warm app surface */\n  --pm-white:   #FFFFFF;   /* Card surface */\n  --pm-error:   #FF4136;   /* Error ONLY — never decoratively */\n  --pm-win:     #1A6B3A;   /* Win state */\n  --pm-loss:    #B52A1C;   /* Loss state */\n  --pm-grey:    #888888;   /* Secondary text */\n  --pm-border:  #DDDAD0;   /* Subtle borders */\n\n  /* ── TYPOGRAPHY ─────────────────────────── */\n  --pm-font-display: 'Unbounded', 'Arial Black', sans-serif;\n  --pm-font-body:    'DM Sans', sans-serif;\n  --pm-font-mono:    'DM Mono', monospace;\n\n  /* ── STROKE WEIGHTS ─────────────────────── */\n  --pm-s1: 1px;   /* Internal subdivisions, row separators */\n  --pm-s2: 2px;   /* Standard default */\n  --pm-s3: 3px;   /* Primary structural */\n\n  /* ── ACCENT STROKES ─────────────────────── */\n  --pm-accent-top:  5px;   /* Category (what card IS) */\n  --pm-accent-left: 4px;   /* Status (what IS HAPPENING) */\n\n  /* ── SPACING (4px base unit) ────────────── */\n  --pm-sp1: 4px;   --pm-sp2: 8px;\n  --pm-sp3: 12px;  --pm-sp4: 16px;\n  --pm-sp5: 20px;  --pm-sp6: 24px;\n  --pm-sp8: 32px;  --pm-sp10: 40px;\n\n  /* ── CONTAINER DETAILS ──────────────────── */\n  --pm-corner-mark:  16px;\n  --pm-inner-inset:  4px;\n\n  /* ── TEXTURE OPACITIES ──────────────────── */\n  --pm-tx-subtle:   0.04;\n  --pm-tx-standard: 0.06;\n  --pm-tx-bold:     0.12;\n\n  /* ── MIN TOUCH TARGET ───────────────────── */\n  --pm-touch-min:   48px;\n}\n\n/* Base body — use cream as app surface */\nbody {\n  background: var(--pm-cream);\n  color: var(--pm-ink);\n  font-family: var(--pm-font-body);\n  margin: 0;\n}\n",
  "tokens.js": "// ═══════════════════════════════════════════════════════════════════\n//  PADELMATCH BRAND KIT — DESIGN TOKENS (JS)\n//  For React / JSX use. Same values as tokens.css.\n// ═══════════════════════════════════════════════════════════════════\n\nexport const T = {\n  // COLOUR\n  lime:    '#C9E52F',\n  blue:    '#1A56FF',\n  purple:  '#6E28D9',\n  ink:     '#111118',\n  cream:   '#F5F2E8',\n  white:   '#FFFFFF',\n  error:   '#FF4136',\n  win:     '#1A6B3A',\n  loss:    '#B52A1C',\n  grey:    '#888888',\n  border:  '#DDDAD0',\n\n  // STROKE WEIGHTS\n  s1: '1px',\n  s2: '2px',\n  s3: '3px',\n\n  // ACCENT STROKES\n  accentTop:  '5px',\n  accentLeft: '4px',\n\n  // SPACING (4px base)\n  sp1: '4px',  sp2: '8px',  sp3: '12px', sp4: '16px',\n  sp5: '20px', sp6: '24px', sp8: '32px', sp10: '40px',\n\n  // CONTAINER DETAILS\n  cornerMark: '16px',\n  innerInset: '4px',\n\n  // TEXTURE OPACITIES\n  txSubtle:   0.04,\n  txStandard: 0.06,\n  txBold:     0.12,\n};\n\nexport const F = {\n  display: \"'Unbounded', 'Arial Black', sans-serif\",\n  body:    \"'DM Sans', sans-serif\",\n  mono:    \"'DM Mono', monospace\",\n};\n\n// Style shortcuts\nexport const ub   = { fontFamily: F.display };\nexport const sans = { fontFamily: F.body };\nexport const mono = { fontFamily: F.mono };\n",
};
